import { useState } from "react";

export default function LiquidGlassCard() {
  const [position, setPosition] = useState({ x: 50, y: 50 });

  const handleMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();

    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    setPosition({ x, y });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#ff4527]">
      <div
        onMouseMove={handleMove}
        className="
          relative
          w-[420px]
          h-[650px]
          rounded-[40px]
          overflow-hidden
          bg-white/10
          backdrop-blur-[30px]
          border border-white/20
        "
      >
        {/* Moving Reflection */}
        <div
          className="
            absolute
            w-60
            h-60
            rounded-full
            pointer-events-none
            blur-3xl
            bg-white/30
            transition-all
            duration-200
          "
          style={{
            left: `${position.x}%`,
            top: `${position.y}%`,
            transform: "translate(-50%,-50%)",
          }}
        />

        {/* Shine Layer */}
        <div
          className="
            absolute inset-0
            bg-gradient-to-br
            from-white/20
            via-transparent
            to-transparent
          "
        />

        <div className="relative z-10 p-8">
          <h1 className="text-white text-5xl font-bold">
            Your money.
            <br />
            Your way.
          </h1>

          <button
            className="
              mt-10
              px-6 py-3
              rounded-2xl
              bg-white/20
              backdrop-blur-md
              border border-white/20
              text-white
            "
          >
            Let's Connect
          </button>
        </div>
      </div>
    </div>
  );
}
